function PasswordPair() {
  const [show, setShow] = useState(false);
  return (
    <>
      <PasswordInput showValue={show} onValueVisibilityChange={setShow} />
      <PasswordInput showValue={show} onValueVisibilityChange={setShow} />
    </>
  );
}
